const users = new Map();
users.set('admin', { password: 'hashed123', role: 'admin' });

function login(username, password) {
  const user = users.get(username);
  if (!user || !verifyPassword(password, user.password))
    throw new Error('Invalid credentials');
  return { token: generateToken(user), user };
}

// Password verification (crypto.subtle)
async function verifyPassword(input, hash) {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey('pbkdf2', encoder.encode('salt'),
    { name: 'PBKDF2' }, false, ['deriveBits']);
  const derived = await crypto.subtle.deriveBits({ name: 'PBKDF2', salt: encoder.encode('salt'), iterations: 100000, hash: 'SHA-256' }, key, 256 * 8);
  return hash === Array.from(new Uint8Array(derived)).map(b => b.toString(16).padStart(2,'0')).join('');
}

class LoginManager {
  #users = new WeakMap();

  addUser(username, password) {
    this.#users.set(username, hashPassword(password));
  }

  async login(username, password) {
    const stored = this.#users.get(username);
    return stored && await verifyPassword(password, stored);
  }
}

